// ============================================================================
// scripts/gen-locale-coverage.mjs
// ----------------------------------------------------------------------------
// Computes, at BUILD time, how completely each locale's message pack covers the
// English source, and writes the result to src/i18n/locale-coverage.ts as a
// plain constant map. The language switcher imports that map to show a per-
// language status cue (green = reviewed, amber = machine-translated & complete,
// yellow = machine-translated & still catching up).
//
// WHY a generated file (not a runtime read): the switcher is a client component
// and the site is a static export, so it cannot read the 16 pack files itself.
// Computing once here keeps the cue accurate and self-maintaining — when a new
// tool ships in EN + pt-BR only (D-56 cadence), the other locales' coverage
// drops below 1.0 automatically and they flip to the "in progress" colour with
// no hand-editing. Runs in the npm `prebuild` step, so it is always fresh.
//
// "Covered" means: the key exists in the locale's own pack AND is a non-empty
// string. A missing or "" key falls back to English at runtime (D-20), so it is
// correctly counted as NOT yet translated for this locale.
// ============================================================================

import { readFileSync, writeFileSync, readdirSync } from "node:fs";
import { join, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const here = dirname(fileURLToPath(import.meta.url));
const msgDir = join(here, "..", "src", "i18n", "messages");
const outFile = join(here, "..", "src", "i18n", "locale-coverage.ts");

/** Flatten a nested message object into a map of dotted-path -> string value. */
function flatten(obj, prefix = "", out = {}) {
  for (const [k, v] of Object.entries(obj)) {
    const path = prefix ? `${prefix}.${k}` : k;
    if (v && typeof v === "object" && !Array.isArray(v)) flatten(v, path, out);
    else out[path] = v;
  }
  return out;
}

// The English pack is the denominator: every key that English defines.
const en = flatten(JSON.parse(readFileSync(join(msgDir, "en.json"), "utf8")));
const enKeys = Object.keys(en).filter((k) => typeof en[k] === "string" && en[k] !== "");
const total = enKeys.length;

const coverage = {};
for (const file of readdirSync(msgDir).filter((f) => f.endsWith(".json"))) {
  const code = file.replace(/\.json$/, "");
  const pack = flatten(JSON.parse(readFileSync(join(msgDir, file), "utf8")));
  // Count English keys that this locale actually translates (present + non-empty).
  const covered = enKeys.filter((k) => typeof pack[k] === "string" && pack[k] !== "").length;
  // Round to 4 decimals so trivial float noise never flips a status.
  coverage[code] = Math.round((covered / total) * 10000) / 10000;
}

// Emit a stable, alphabetically-keyed constant module.
const ordered = Object.keys(coverage).sort();
const body = ordered.map((c) => `  ${JSON.stringify(c)}: ${coverage[c]},`).join("\n");
const out = `// AUTO-GENERATED by scripts/gen-locale-coverage.mjs — do not edit by hand.
// Fraction (0..1) of English message keys that each locale's own pack translates.
// Regenerated on every build (npm prebuild). Drives the language-switcher status cue.
// English is the source language, so its coverage is 1 by definition.

export const LOCALE_COVERAGE: Record<string, number> = {
${body}
};

/** English keys counted at generation time (the denominator). */
export const LOCALE_COVERAGE_DENOMINATOR = ${total};
`;

writeFileSync(outFile, out, "utf8");
console.log(`[gen-locale-coverage] wrote ${outFile} for ${ordered.length} locales (denominator ${total} keys)`);
